import{_ as d,o as r,c as e,ag as a}from"./chunks/framework.CvgP6Fyv.js";const m=JSON.parse('{"title":"パラメータリファレンス","description":"","frontmatter":{},"headers":[],"relativePath":"reference/parameters.md","filePath":"reference/parameters.md"}'),o={name:"reference/parameters.md"};function n(i,t,l,h,s,b){return r(),e("div",null,[...t[0]||(t[0]=[a(`<h1 id="パラメータリファレンス" tabindex="-1">パラメータリファレンス <a class="header-anchor" href="#パラメータリファレンス" aria-label="Permalink to &quot;パラメータリファレンス&quot;">​</a></h1><p>各クラスタータイプには固有の <strong>inputParameters</strong> があり、入力欄の振る舞いを細かく制御できます。クラスターエディタのプロパティパネルで視覚的に編集できます。</p><hr><h2 id="パラメータの形式" tabindex="-1">パラメータの形式 <a class="header-anchor" href="#パラメータの形式" aria-label="Permalink to &quot;パラメータの形式&quot;">​</a></h2><p>内部的には <code>key=value;key=value</code> のセミコロン区切り文字列で保持されます。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Required=1;Align=Left;FontSize=11;Lines=2</span></span></code></pre></div><p>エディタではフォーム UI で編集できるため、通常この形式を意識する必要はありません。</p><hr><h2 id="キーボードテキスト-keyboardtext" tabindex="-1">キーボードテキスト (KeyboardText) <a class="header-anchor" href="#キーボードテキスト-keyboardtext" aria-label="Permalink to &quot;キーボードテキスト (KeyboardText)&quot;">​</a></h2><p>一般的なテキスト入力欄のパラメータです。</p><table tabindex="0"><thead><tr><th>パラメータ</th><th>型</th><th>初期値</th><th>説明</th></tr></thead><tbody><tr><td>Required</td><td>boolean</td><td>OFF</td><td>必須入力にする</td></tr><tr><td>MaxLength</td><td>number</td><td>0</td><td>最大文字数（0 = 無制限）</td></tr><tr><td>InputRestriction</td><td>enum</td><td>(なし)</td><td>入力制限: Number, Email, Url</td></tr><tr><td>Lines</td><td>number</td><td>1</td><td>行数（2以上で複数行テキスト）</td></tr><tr><td>Align</td><td>enum</td><td>Left</td><td>水平配置: Left, Center, Right</td></tr><tr><td>VerticalAlignment</td><td>enum</td><td>Top</td><td>垂直配置: Top, Center, Bottom</td></tr><tr><td>Font</td><td>string</td><td>MS Gothic</td><td>書体</td></tr><tr><td>FontSize</td><td>number</td><td>11</td><td>文字サイズ (pt)</td></tr><tr><td>DefaultFontSize</td><td>number</td><td>11</td><td>デフォルトの文字サイズ</td></tr><tr><td>Weight</td><td>enum</td><td>Normal</td><td>太さ: Normal, Bold</td></tr><tr><td>Color</td><td>string</td><td>0,0,0</td><td>文字色 (R,G,B)</td></tr><tr><td>FontPriority</td><td>boolean</td><td>OFF</td><td>フォント設定を優先</td></tr><tr><td>EnableAutoFontSize</td><td>boolean</td><td>OFF</td><td>文字数に応じて自動縮小</td></tr><tr><td>DefaultText</td><td>string</td><td>(空)</td><td>デフォルトテキスト</td></tr><tr><td>Locked</td><td>boolean</td><td>OFF</td><td>ロック（編集不可）</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">よく使う設定</p><ul><li><strong>氏名欄</strong>: Required=ON, Lines=1</li><li><strong>住所欄</strong>: Lines=2</li><li><strong>備考欄</strong>: Lines=3〜5, EnableAutoFontSize=ON</li></ul></div><hr><h2 id="数値-inputnumeric" tabindex="-1">数値 (InputNumeric) <a class="header-anchor" href="#数値-inputnumeric" aria-label="Permalink to &quot;数値 (InputNumeric)&quot;">​</a></h2><p>数値入力欄のパラメータです。</p><table tabindex="0"><thead><tr><th>パラメータ</th><th>型</th><th>初期値</th><th>説明</th></tr></thead><tbody><tr><td>Required</td><td>boolean</td><td>OFF</td><td>必須入力</td></tr><tr><td>Minimum</td><td>string</td><td>(空)</td><td>最小値</td></tr><tr><td>Maximum</td><td>string</td><td>(空)</td><td>最大値</td></tr><tr><td>Decimal</td><td>number</td><td>0</td><td>小数点以下の桁数</td></tr><tr><td>Comma</td><td>boolean</td><td>OFF</td><td>桁区切りカンマ表示</td></tr><tr><td>Prefix</td><td>string</td><td>(空)</td><td>接頭文字（例: ¥）</td></tr><tr><td>Suffix</td><td>string</td><td>(空)</td><td>接尾文字（例: 円, kg, ℃）</td></tr><tr><td>Align</td><td>enum</td><td>Right</td><td>水平配置</td></tr><tr><td>VerticalAlignment</td><td>enum</td><td>Center</td><td>垂直配置</td></tr><tr><td>Font</td><td>string</td><td>MS Gothic</td><td>書体</td></tr><tr><td>FontSize</td><td>number</td><td>11</td><td>文字サイズ</td></tr><tr><td>Weight</td><td>enum</td><td>Normal</td><td>太さ</td></tr><tr><td>Color</td><td>string</td><td>0,0,0</td><td>文字色</td></tr><tr><td>EnableAutoFontSize</td><td>boolean</td><td>OFF</td><td>自動フォントサイズ</td></tr><tr><td>Locked</td><td>boolean</td><td>OFF</td><td>ロック</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">よく使う設定</p><ul><li><strong>金額</strong>: Comma=ON, Suffix=円</li><li><strong>温度</strong>: Decimal=1, Suffix=℃</li><li><strong>パーセント</strong>: Decimal=1, Suffix=%</li></ul></div><hr><h2 id="年月日-date" tabindex="-1">年月日 (Date) <a class="header-anchor" href="#年月日-date" aria-label="Permalink to &quot;年月日 (Date)&quot;">​</a></h2><p>日付入力のパラメータです。</p><table tabindex="0"><thead><tr><th>パラメータ</th><th>型</th><th>初期値</th><th>説明</th></tr></thead><tbody><tr><td>Required</td><td>boolean</td><td>OFF</td><td>必須入力</td></tr><tr><td>AutoInput</td><td>boolean</td><td>OFF</td><td>帳票作成時に自動入力</td></tr><tr><td>DateFormat</td><td>enum</td><td>yyyy/MM/dd</td><td>日付書式</td></tr><tr><td>FirstOnly</td><td>boolean</td><td>OFF</td><td>初回入力のみ（変更不可）</td></tr><tr><td>Editable</td><td>boolean</td><td>ON</td><td>編集可能</td></tr><tr><td>ConfirmDialog</td><td>boolean</td><td>OFF</td><td>入力時に確認ダイアログ</td></tr><tr><td>UseTime</td><td>boolean</td><td>OFF</td><td>時刻も併せて入力</td></tr><tr><td>TimeFormat</td><td>enum</td><td>HH:mm</td><td>時刻書式: HH:mm, HH:mm:ss</td></tr><tr><td>Font</td><td>string</td><td>MS Gothic</td><td>書体</td></tr><tr><td>FontSize</td><td>number</td><td>11</td><td>文字サイズ</td></tr><tr><td>Weight</td><td>enum</td><td>Normal</td><td>太さ</td></tr><tr><td>Color</td><td>string</td><td>0,0,0</td><td>文字色</td></tr><tr><td>Align</td><td>enum</td><td>Left</td><td>配置</td></tr><tr><td>Locked</td><td>boolean</td><td>OFF</td><td>ロック</td></tr></tbody></table><p><strong>日付書式の選択肢:</strong></p><ul><li><code>yyyy/MM/dd</code> → 2026/03/28</li><li><code>yyyy-MM-dd</code> → 2026-03-28</li><li><code>MM/dd</code> → 03/28</li><li><code>yyyy年MM月dd日</code> → 2026年03月28日</li></ul><hr><h2 id="時刻-time" tabindex="-1">時刻 (Time) <a class="header-anchor" href="#時刻-time" aria-label="Permalink to &quot;時刻 (Time)&quot;">​</a></h2><p>時刻入力のパラメータです。</p><table tabindex="0"><thead><tr><th>パラメータ</th><th>型</th><th>初期値</th><th>説明</th></tr></thead><tbody><tr><td>Required</td><td>boolean</td><td>OFF</td><td>必須入力</td></tr><tr><td>AutoInput</td><td>boolean</td><td>OFF</td><td>自動入力</td></tr><tr><td>TimeFormat</td><td>enum</td><td>HH:mm</td><td>時刻書式: HH:mm, HH:mm:ss, H:mm</td></tr><tr><td>FirstOnly</td><td>boolean</td><td>OFF</td><td>初回のみ</td></tr><tr><td>Editable</td><td>boolean</td><td>ON</td><td>編集可能</td></tr><tr><td>Font</td><td>string</td><td>MS Gothic</td><td>書体</td></tr><tr><td>FontSize</td><td>number</td><td>11</td><td>文字サイズ</td></tr><tr><td>Weight</td><td>enum</td><td>Normal</td><td>太さ</td></tr><tr><td>Color</td><td>string</td><td>0,0,0</td><td>文字色</td></tr><tr><td>Align</td><td>enum</td><td>Left</td><td>配置</td></tr><tr><td>Locked</td><td>boolean</td><td>OFF</td><td>ロック</td></tr></tbody></table><hr><h2 id="計算式-calculate" tabindex="-1">計算式 (Calculate) <a class="header-anchor" href="#計算式-calculate" aria-label="Permalink to &quot;計算式 (Calculate)&quot;">​</a></h2><p>自動計算フィールドのパラメータです。</p><table tabindex="0"><thead><tr><th>パラメータ</th><th>型</th><th>初期値</th><th>説明</th></tr></thead><tbody><tr><td>Function</td><td>string</td><td>(空)</td><td>計算式（ConMas 式構文）</td></tr><tr><td>FunctionVersion</td><td>number</td><td>1</td><td>計算式バージョン</td></tr><tr><td>Decimal</td><td>number</td><td>0</td><td>小数点以下の桁数</td></tr><tr><td>Comma</td><td>boolean</td><td>OFF</td><td>桁区切り</td></tr><tr><td>Minimum</td><td>string</td><td>(空)</td><td>最小値</td></tr><tr><td>Maximum</td><td>string</td><td>(空)</td><td>最大値</td></tr><tr><td>DataType</td><td>enum</td><td>Numeric</td><td>データ型: Numeric, DateTime, String</td></tr><tr><td>Visible</td><td>boolean</td><td>ON</td><td>表示/非表示</td></tr><tr><td>Align</td><td>enum</td><td>Right</td><td>配置</td></tr><tr><td>Font</td><td>string</td><td>MS Gothic</td><td>書体</td></tr><tr><td>FontSize</td><td>number</td><td>11</td><td>文字サイズ</td></tr><tr><td>Weight</td><td>enum</td><td>Normal</td><td>太さ</td></tr><tr><td>Color</td><td>string</td><td>0,0,0</td><td>文字色</td></tr><tr><td>Locked</td><td>boolean</td><td>OFF</td><td>ロック</td></tr></tbody></table><hr><h2 id="単一選択-select" tabindex="-1">単一選択 (Select) <a class="header-anchor" href="#単一選択-select" aria-label="Permalink to &quot;単一選択 (Select)&quot;">​</a></h2><p>ドロップダウン等で1つを選ぶパラメータです。</p><table tabindex="0"><thead><tr><th>パラメータ</th><th>型</th><th>初期値</th><th>説明</th></tr></thead><tbody><tr><td>Required</td><td>boolean</td><td>OFF</td><td>必須入力</td></tr><tr><td>Items</td><td>string</td><td>(空)</td><td>選択肢 ID（カンマ区切り）</td></tr><tr><td>Labels</td><td>string</td><td>(空)</td><td>選択肢ラベル（カンマ区切り）</td></tr><tr><td>Default</td><td>string</td><td>(空)</td><td>初期選択値</td></tr><tr><td>Display</td><td>enum</td><td>Dropdown</td><td>表示形式: Dropdown, Radio, Button</td></tr><tr><td>ToggleInput</td><td>boolean</td><td>OFF</td><td>トグル入力</td></tr><tr><td>Font</td><td>string</td><td>MS Gothic</td><td>書体</td></tr><tr><td>FontSize</td><td>number</td><td>11</td><td>文字サイズ</td></tr><tr><td>Weight</td><td>enum</td><td>Normal</td><td>太さ</td></tr><tr><td>Color</td><td>string</td><td>0,0,0</td><td>文字色</td></tr><tr><td>Align</td><td>enum</td><td>Left</td><td>配置</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">選択肢の設定例</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Items=1,2,3</span></span>
<span class="line"><span>Labels=良,可,不可</span></span></code></pre></div><p>Items と Labels は同じ数にしてください。</p></div><hr><h2 id="複数選択-multiselect" tabindex="-1">複数選択 (MultiSelect) <a class="header-anchor" href="#複数選択-multiselect" aria-label="Permalink to &quot;複数選択 (MultiSelect)&quot;">​</a></h2><p>複数の選択肢を選べるパラメータです。</p><table tabindex="0"><thead><tr><th>パラメータ</th><th>型</th><th>初期値</th><th>説明</th></tr></thead><tbody><tr><td>Items</td><td>string</td><td>(空)</td><td>選択肢 ID（カンマ区切り）</td></tr><tr><td>Labels</td><td>string</td><td>(空)</td><td>選択肢ラベル（カンマ区切り）</td></tr><tr><td>Selected</td><td>string</td><td>(空)</td><td>選択済み</td></tr><tr><td>Punctuation</td><td>string</td><td>,</td><td>区切り文字</td></tr><tr><td>Default</td><td>string</td><td>(空)</td><td>初期値</td></tr><tr><td>Display</td><td>enum</td><td>Dropdown</td><td>表示形式: Dropdown, Radio, Button</td></tr><tr><td>Font</td><td>string</td><td>MS Gothic</td><td>書体</td></tr><tr><td>FontSize</td><td>number</td><td>11</td><td>文字サイズ</td></tr><tr><td>Weight</td><td>enum</td><td>Normal</td><td>太さ</td></tr><tr><td>Color</td><td>string</td><td>0,0,0</td><td>文字色</td></tr><tr><td>Align</td><td>enum</td><td>Left</td><td>配置</td></tr></tbody></table><hr><h2 id="チェック-check" tabindex="-1">チェック (Check) <a class="header-anchor" href="#チェック-check" aria-label="Permalink to &quot;チェック (Check)&quot;">​</a></h2><p>チェックボックスのパラメータです。</p><table tabindex="0"><thead><tr><th>パラメータ</th><th>型</th><th>初期値</th><th>説明</th></tr></thead><tbody><tr><td>Required</td><td>boolean</td><td>OFF</td><td>必須入力</td></tr><tr><td>Marker</td><td>enum</td><td>Check</td><td>マーカー種類: Check, Circle, Cross, Fill</td></tr><tr><td>LineColor</td><td>string</td><td>0,0,0</td><td>線色 (R,G,B)</td></tr><tr><td>LineWidth</td><td>number</td><td>2</td><td>線幅</td></tr><tr><td>BrushColor</td><td>string</td><td>255,0,0</td><td>塗り色 (R,G,B)</td></tr><tr><td>Group</td><td>string</td><td>(空)</td><td>グループ名（排他チェック用）</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">グループの使い方</p><p>同じ Group 名を持つチェックボックスは排他選択（ラジオボタン風）になります。例えば「合格」「不合格」の2つに同じグループ名を設定すると、片方をチェックするともう片方が外れます。</p></div><hr><h2 id="画像-image" tabindex="-1">画像 (Image) <a class="header-anchor" href="#画像-image" aria-label="Permalink to &quot;画像 (Image)&quot;">​</a></h2><p>写真・画像添付のパラメータです。</p><table tabindex="0"><thead><tr><th>パラメータ</th><th>型</th><th>初期値</th><th>説明</th></tr></thead><tbody><tr><td>Required</td><td>boolean</td><td>OFF</td><td>必須入力</td></tr><tr><td>IsOriginal</td><td>boolean</td><td>OFF</td><td>原寸表示</td></tr><tr><td>ImageSize</td><td>number</td><td>0</td><td>画像サイズ</td></tr><tr><td>EnableShortcut</td><td>boolean</td><td>OFF</td><td>ショートカット有効</td></tr><tr><td>PhotoDate</td><td>boolean</td><td>OFF</td><td>撮影日時を記録</td></tr></tbody></table><hr><h2 id="手書きデジタル-handwriting" tabindex="-1">手書きデジタル (Handwriting) <a class="header-anchor" href="#手書きデジタル-handwriting" aria-label="Permalink to &quot;手書きデジタル (Handwriting)&quot;">​</a></h2><p>手書き入力のパラメータです。</p><table tabindex="0"><thead><tr><th>パラメータ</th><th>型</th><th>初期値</th><th>説明</th></tr></thead><tbody><tr><td>Required</td><td>boolean</td><td>OFF</td><td>必須入力</td></tr><tr><td>Lines</td><td>number</td><td>1</td><td>行数</td></tr><tr><td>FontPriority</td><td>boolean</td><td>OFF</td><td>フォント優先</td></tr><tr><td>Align</td><td>enum</td><td>Left</td><td>水平配置</td></tr><tr><td>VerticalAlignment</td><td>enum</td><td>Top</td><td>垂直配置</td></tr><tr><td>Font</td><td>string</td><td>MS Gothic</td><td>書体</td></tr><tr><td>FontSize</td><td>number</td><td>11</td><td>文字サイズ</td></tr><tr><td>Weight</td><td>enum</td><td>Normal</td><td>太さ</td></tr><tr><td>Color</td><td>string</td><td>0,0,0</td><td>文字色</td></tr><tr><td>EnableAutoFontSize</td><td>boolean</td><td>OFF</td><td>自動フォントサイズ</td></tr><tr><td>Locked</td><td>boolean</td><td>OFF</td><td>ロック</td></tr></tbody></table><hr><h2 id="手書きノート形式-fixedtext" tabindex="-1">手書きノート形式 (FixedText) <a class="header-anchor" href="#手書きノート形式-fixedtext" aria-label="Permalink to &quot;手書きノート形式 (FixedText)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>パラメータ</th><th>型</th><th>初期値</th><th>説明</th></tr></thead><tbody><tr><td>Required</td><td>boolean</td><td>OFF</td><td>必須入力</td></tr><tr><td>Lines</td><td>number</td><td>1</td><td>行数</td></tr><tr><td>Width</td><td>number</td><td>3</td><td>線幅</td></tr><tr><td>Color</td><td>string</td><td>0,0,0</td><td>線色</td></tr></tbody></table><hr><h2 id="カレンダー年月日-calendardate" tabindex="-1">カレンダー年月日 (CalendarDate) <a class="header-anchor" href="#カレンダー年月日-calendardate" aria-label="Permalink to &quot;カレンダー年月日 (CalendarDate)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>パラメータ</th><th>型</th><th>初期値</th><th>説明</th></tr></thead><tbody><tr><td>Required</td><td>boolean</td><td>OFF</td><td>必須入力</td></tr><tr><td>AutoInput</td><td>boolean</td><td>OFF</td><td>自動入力</td></tr><tr><td>DateFormat</td><td>enum</td><td>yyyy/MM/dd</td><td>日付書式</td></tr><tr><td>FirstOnly</td><td>boolean</td><td>OFF</td><td>初回のみ</td></tr><tr><td>Editable</td><td>boolean</td><td>ON</td><td>編集可能</td></tr><tr><td>ConfirmDialog</td><td>boolean</td><td>OFF</td><td>確認ダイアログ</td></tr><tr><td>Day</td><td>string</td><td>(空)</td><td>基準日オフセット</td></tr><tr><td>UseTime</td><td>boolean</td><td>OFF</td><td>時刻併用</td></tr><tr><td>TimeFormat</td><td>enum</td><td>HH:mm</td><td>時刻書式</td></tr><tr><td>Font</td><td>string</td><td>MS Gothic</td><td>書体</td></tr><tr><td>FontSize</td><td>number</td><td>11</td><td>文字サイズ</td></tr><tr><td>Weight</td><td>enum</td><td>Normal</td><td>太さ</td></tr><tr><td>Color</td><td>string</td><td>0,0,0</td><td>文字色</td></tr><tr><td>Align</td><td>enum</td><td>Left</td><td>配置</td></tr><tr><td>Locked</td><td>boolean</td><td>OFF</td><td>ロック</td></tr></tbody></table><hr><h2 id="共通パラメータ" tabindex="-1">共通パラメータ <a class="header-anchor" href="#共通パラメータ" aria-label="Permalink to &quot;共通パラメータ&quot;">​</a></h2><p>多くのタイプに共通して使われるパラメータです。</p><table tabindex="0"><thead><tr><th>パラメータ</th><th>説明</th><th>補足</th></tr></thead><tbody><tr><td>Required</td><td>必須入力フラグ</td><td>0 = 任意, 1 = 必須</td></tr><tr><td>Font</td><td>書体名</td><td>例: MS Gothic, MS Mincho</td></tr><tr><td>FontSize</td><td>文字サイズ (pt)</td><td>一般的に 9〜14</td></tr><tr><td>Weight</td><td>文字の太さ</td><td>Normal または Bold</td></tr><tr><td>Color</td><td>文字色</td><td>R,G,B 形式（例: 0,0,0 = 黒）</td></tr><tr><td>Align</td><td>水平配置</td><td>Left, Center, Right</td></tr><tr><td>Locked</td><td>ロック</td><td>1 にすると入力不可</td></tr></tbody></table>`,63)])])}const c=d(o,[["render",n]]);export{m as __pageData,c as default};
